// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import static org.assertj.core.api.Assertions.assertThat;

import java.lang.reflect.RecordComponent;
import java.util.Arrays;

import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.junit.jupiter.api.Test;

class PackedPlannerBoundaryTest {

	@Test
	void publicResultContainsOnlyDetachedSelectedPlanState() throws ReflectiveOperationException {
		CascadesPlan plan = new CascadesPlanner().optimize(new SingletonSet(), OptimizationGoal.root());

		assertThat(Arrays.stream(CascadesPlan.class.getRecordComponents())
				.map(RecordComponent::getName))
						.containsExactly("tupleExpr", "cost", "searchStatus", "provenance", "metrics");
		assertThat(plan.tupleExpr()).isNotNull();
		assertThat(plan.cost()).isNotNull();
		assertThat(plan.searchStatus()).isNotNull();
		assertThat(plan.provenance()).isNotNull();
		assertThat(componentValue(plan, "metrics")).isNotNull();
	}

	@Test
	void legacyObjectPlannerConstructorsAreAbsent() {
		assertThat(CascadesPlanner.class.getConstructors())
				.allSatisfy(constructor -> assertThat(constructor.getParameterCount()).isZero());
	}

	@Test
	void onlyUnifiedProductionSearchModesRemain() {
		assertThat(OptimizationGoal.SearchMode.values())
				.extracting(Enum::name)
				.containsExactly("AUTO", "EXACT", "BUDGETED");
	}

	private static Object componentValue(CascadesPlan plan, String componentName) throws ReflectiveOperationException {
		return CascadesPlan.class.getDeclaredMethod(componentName).invoke(plan);
	}
}
